/// Pre-compiled CUDA DMA helper module. Compiled once (at first use) and reused
/// across all iterations to eliminate per-call PyModule::from_code overhead.
/// Maintains persistent state: pinned host pointers, pre-allocated GPU buffers.
static CUDA_HELPERS: LazyLock<std::sync::Mutex<Option<Py<PyModule>>>> =
    LazyLock::new(|| std::sync::Mutex::new(None));

/// Counter to make pinned memory buffer IDs unique across registrations.
static PINNED_COUNTER: LazyLock<std::sync::Mutex<u64>> =
    LazyLock::new(|| std::sync::Mutex::new(0));

/// Tracks freed pool buffer IDs so the DORADMA fast path can detect
/// read-after-free. Entries are inserted on free_memory_pool and naturally
/// bounded since each registration creates a unique counter-based ID.
static FREED_POOL_IDS: LazyLock<std::sync::Mutex<HashSet<String>>> =
    LazyLock::new(|| std::sync::Mutex::new(HashSet::new()));

/// Per-pool persistent state.
/// Keeping Shmem alive prevents munmap, preserving stable mmap addresses
/// for pool-hit detection across `register_memory_pool` calls.
///
/// # Safety
/// `Shmem` is not `Send + Sync` due to raw pointer fields, but `PoolSlot`
/// is always stored behind a `Mutex` and `_shmem` is never accessed after
/// initialization — it is only kept alive for its destructor.
struct PoolSlot {
    _shmem: shared_memory_extended::Shmem,
    base: u64,
    size: usize,
    gpu_va: u64,
}

unsafe impl Send for PoolSlot {}
unsafe impl Sync for PoolSlot {}

/// Persistent pool storage — stable mmap addresses for zero-copy detection.
/// Keyed by counter (unique per registration), supports unlimited pools.
static PINNED_POOL: LazyLock<std::sync::Mutex<HashMap<u64, PoolSlot>>> =
    LazyLock::new(|| std::sync::Mutex::new(HashMap::new()));

/// Receiver-side GPU cache per pool.
/// Keeps Shmem alive to prevent munmap, preserving stable mmap addresses
/// and valid GPU VAs for zero-copy reads across iterations.
struct RecvGpuSlot {
    _shmem: shared_memory_extended::Shmem,
    gpu_va: u64,
    gpu_buf: u64,  // IPC-opened GPU DRAM pointer, 0 if using GPU VA path
}
unsafe impl Send for RecvGpuSlot {}
unsafe impl Sync for RecvGpuSlot {}

/// Receiver-side per-pool cache keeping Shmem alive + GPU VA for zero-copy reads.
/// Set up lazily in try_doradma_read: open shmem, cudaHostRegister,
/// cudaHostGetDevicePointer, then cache both Shmem and GPU VA.
static RECV_GPU_VA: LazyLock<std::sync::Mutex<HashMap<u64, RecvGpuSlot>>> =
    LazyLock::new(|| std::sync::Mutex::new(HashMap::new()));

/// Receiver-side per-pool Shmem cache for CPU receivers.
/// Keeps Shmem alive to prevent munmap of the CPU pointer returned
/// by the as_cuda=False path in try_doradma_read.
struct RecvCpuSlot {
    _shmem: shared_memory_extended::Shmem,
}
unsafe impl Send for RecvCpuSlot {}
unsafe impl Sync for RecvCpuSlot {}

/// Receiver-side per-pool cache keeping Shmem alive for CPU zero-copy reads.
/// Without this cache, the Shmem handle drops at the end of try_doradma_read,
/// triggering munmap and making the returned CPU pointer a dangling pointer.
static RECV_CPU_SHMEM: LazyLock<std::sync::Mutex<HashMap<u64, RecvCpuSlot>>> =
    LazyLock::new(|| std::sync::Mutex::new(HashMap::new()));

/// Get (or compile) the persistent CUDA DMA helper module.
///
/// Compiled once at first use and reused across all subsequent iterations.
/// The module maintains internal state for pinned host pointers and GPU buffers,
/// eliminating per-call cudaHostRegister/cudaMalloc/cudaFree/shm_open overhead.
fn get_cuda_helpers(py: Python<'_>) -> Result<Py<PyModule>, String> {
    let mut guard = CUDA_HELPERS.lock().unwrap();
    if let Some(ref module) = *guard {
        return Ok(module.clone_ref(py));
    }

    let code = r#"
import ctypes
_lib = ctypes.CDLL('libcudart.so')

_lib.cudaHostRegister.restype = ctypes.c_int
_lib.cudaHostRegister.argtypes = [ctypes.c_void_p, ctypes.c_size_t, ctypes.c_uint]

_lib.cudaHostUnregister.restype = ctypes.c_int
_lib.cudaHostUnregister.argtypes = [ctypes.c_void_p]

_lib.cudaMalloc.restype = ctypes.c_int
_lib.cudaMalloc.argtypes = [ctypes.POINTER(ctypes.c_void_p), ctypes.c_size_t]

_lib.cudaMemcpy.restype = ctypes.c_int
_lib.cudaMemcpy.argtypes = [ctypes.c_void_p, ctypes.c_void_p, ctypes.c_size_t, ctypes.c_int]

_lib.cudaFree.restype = ctypes.c_int
_lib.cudaFree.argtypes = [ctypes.c_void_p]

_lib.cudaDeviceSynchronize.restype = ctypes.c_int

_lib.cudaHostGetDevicePointer.restype = ctypes.c_int
_lib.cudaHostGetDevicePointer.argtypes = [ctypes.POINTER(ctypes.c_void_p), ctypes.c_void_p, ctypes.c_uint]

cudaMemcpyHostToDevice = 1

# IPC handle struct — must be a Structure subclass so ctypes passes it
# by value (64 bytes on the stack) to cudaIpcOpenMemHandle.
class _CudaIpcMemHandle(ctypes.Structure):
    _fields_ = [("reserved", ctypes.c_byte * 64)]

_lib.cudaIpcGetMemHandle.restype = ctypes.c_int
_lib.cudaIpcGetMemHandle.argtypes = [ctypes.POINTER(_CudaIpcMemHandle), ctypes.c_void_p]

_lib.cudaIpcOpenMemHandle.restype = ctypes.c_int
_lib.cudaIpcOpenMemHandle.argtypes = [ctypes.POINTER(ctypes.c_void_p), _CudaIpcMemHandle, ctypes.c_uint]

# Persistent state: per-slot GPU buffer cache
_gpu_bufs = {}    # slot -> (d_ptr, size)

def _register_host(ptr, size):
    """Pin host memory. Idempotent — error 712 (already registered) is ok."""
    err = _lib.cudaHostRegister(ctypes.c_void_p(ptr), size, 0)
    if err != 0 and err != 712:
        raise RuntimeError(f'cudaHostRegister(0x{ptr:x}, {size}) failed: {err}')

def _unregister_host(ptr):
    """Unpin host memory."""
    err = _lib.cudaHostUnregister(ctypes.c_void_p(ptr))
    if err != 0 and err != 713:
        raise RuntimeError(f'cudaHostUnregister(0x{ptr:x}) failed: {err}')

def _get_device_ptr(host_ptr):
    """Get a GPU VA for a pinned host memory region."""
    d_ptr = ctypes.c_void_p()
    err = _lib.cudaHostGetDevicePointer(ctypes.byref(d_ptr), ctypes.c_void_p(host_ptr), 0)
    if err != 0:
        raise RuntimeError(f'cudaHostGetDevicePointer(0x{host_ptr:x}) failed: {err}')
    return d_ptr.value


def _cuda_memcpy(dst, src, size, kind):
    """cudaMemcpy wrapper. kind: 1=H2D, 2=D2H, 3=D2D."""
    err = _lib.cudaMemcpy(ctypes.c_void_p(dst), ctypes.c_void_p(src), size, kind)
    if err != 0:
        raise RuntimeError(f"cudaMemcpy(0x{dst:x}, 0x{src:x}, {size}, {kind}) failed: {err}")
    _lib.cudaDeviceSynchronize()

def _get_gpu_buf(slot, size):
    """Get or allocate a GPU buffer for the given slot. Reuses when size matches."""
    if slot in _gpu_bufs and _gpu_bufs[slot][1] >= size:
        return _gpu_bufs[slot][0]
    if slot in _gpu_bufs:
        _lib.cudaFree(ctypes.c_void_p(_gpu_bufs[slot][0]))
    d_ptr = ctypes.c_void_p()
    err = _lib.cudaMalloc(ctypes.byref(d_ptr), size)
    if err != 0:
        raise RuntimeError(f'cudaMalloc({size}) failed: {err}')
    _gpu_bufs[slot] = (d_ptr.value, size)
    return d_ptr.value

def _ipc_export(d_ptr):
    """Export GPU memory for cross-process sharing. Returns 64-byte handle."""
    handle = _CudaIpcMemHandle()
    err = _lib.cudaIpcGetMemHandle(ctypes.byref(handle), ctypes.c_void_p(d_ptr))
    if err != 0:
        raise RuntimeError(f'cudaIpcGetMemHandle(0x{d_ptr:x}) failed: {err}')
    return bytes(handle)

def _ipc_import(handle_bytes):
    """Import GPU memory from another process. Returns device pointer.

    cudaIpcOpenMemHandle takes the handle struct BY VALUE (64 bytes on
    the stack). _CudaIpcMemHandle.from_buffer_copy reconstructs the struct
    and ctypes copies it onto the stack for the call.
    """
    handle = _CudaIpcMemHandle.from_buffer_copy(handle_bytes)
    d_ptr = ctypes.c_void_p()
    err = _lib.cudaIpcOpenMemHandle(ctypes.byref(d_ptr), handle, 1)
    if err != 0:
        raise RuntimeError(f'cudaIpcOpenMemHandle failed: {err}')
    _lib.cudaDeviceSynchronize()
    return d_ptr.value

def dma_copy(ptr, size, slot):
    """DMA transfer from host to pre-allocated GPU buffer.

    Pins source memory, copies via cudaMemcpyHtoD (DMA engine),
    then unpins. Returns the device pointer of the pooled GPU buffer.
    """
    _register_host(ptr, size)
    try:
        d_ptr = _get_gpu_buf(slot, size)
        err = _lib.cudaMemcpy(
            ctypes.c_void_p(d_ptr),
            ctypes.c_void_p(ptr),
            size,
            cudaMemcpyHostToDevice,
        )
        if err != 0:
            raise RuntimeError(f'cudaMemcpy failed: {err}')
        _lib.cudaDeviceSynchronize()
    finally:
        _unregister_host(ptr)
    return d_ptr

"#;

    let code_cstr = std::ffi::CString::new(code)
        .map_err(|e| format!("CString: {}", e))?;
    let bound_module = PyModule::from_code(py, code_cstr.as_c_str(), c"_cuda_helpers.py", c"_cuda_helpers")
        .map_err(|e| format!("CUDA helper compile failed: {}", e))?;
    let module_ref: Py<PyModule> = bound_module.unbind();
    *guard = Some(module_ref.clone_ref(py));
    Ok(module_ref)
}

static RUNTIME: LazyLock<Runtime> = LazyLock::new(|| {
    Builder::new_multi_thread()
        .worker_threads(4)
        .enable_all()
        .build()
        .context("Failed to create Tokio runtime")
        .unwrap()
});

/// Consume a Python `logging.LogRecord` and emit a Rust `tracing::Event` instead.
#[pyfunction]
fn host_log<'py>(record: Bound<'py, PyAny>) -> PyResult<()> {
    let level = record.getattr("levelno")?.extract::<u8>()?;
    let message = record.getattr("getMessage")?.call0()?.to_string();
    let pathname = record.getattr("pathname")?.to_string();
    let lineno = record.getattr("lineno")?.to_string();
    let target = record.getattr("name")?.to_string();

    RUNTIME.spawn(async move {
    if level.ge(&40u8) {
        let span = span!(Level::ERROR, "dora.python.log.error", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::ERROR, file=pathname, line=lineno, %target, %message);
    } else if level.ge(&30u8) {
        let span = span!(Level::WARN, "dora.python.log.warn", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::WARN, file=pathname, line=lineno, %target, %message);
    } else if level.ge(&20u8){
        let span = span!(Level::INFO, "dora.python.log.info", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::INFO, file=pathname, line=lineno, %target, %message);
    } else if level.ge(&10u8) {
        let span = span!(Level::DEBUG, "dora.python.log.debug", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::DEBUG, file=pathname, line=lineno, %target, %message);
    } else {
        let span = span!(Level::TRACE, "dora.python.log.trace", file=pathname, line=lineno, %target, %message);
        let _enter = span.enter();
        tracing::event!(tracing::Level::TRACE, file=pathname, line=lineno, %target, %message);
    }
    });
    Ok(())
}

/// Modifies the Python `logging` module to deliver its log messages to the host `tracing::Subscriber` by default.
/// To achieve this goal, the following changes are made to the module:
/// - A new builtin function `logging.host_log` transcodes `logging.LogRecord`s to `tracing::Event`s. This function
///   is not exported in `logging.__all__`, as it is not intended to be called directly.
/// - A new class `logging.HostHandler` provides a `logging.Handler` that delivers all records to `host_log`.
/// - `logging.basicConfig` is changed to use `logging.HostHandler` by default.
///
/// Since any call like `logging.warn(...)` sets up logging via `logging.basicConfig`, all log messages are now
/// delivered to `crate::host_log`, which will send them to `tracing::event!`.
pub fn setup_logging(py: Python) -> PyResult<()> {
    let logging = py.import("logging")?;
    logging.setattr("host_log", wrap_pyfunction!(host_log, &logging)?)?;
    py.run(
        cr#"
class HostHandler(Handler):
	def __init__(self, level=0):
		super().__init__(level=level)
	
	def emit(self, record):
		host_log(record)

oldBasicConfig = basicConfig

def basicConfig(*pargs, **kwargs):
	if "handlers" not in kwargs:
		kwargs["handlers"] = [HostHandler()]
	else:
		kwargs["handlers"].append(HostHandler())
	if "level" not in kwargs:
		kwargs["level"] = 0

	return oldBasicConfig(*pargs, **kwargs)
"#,
        Some(&logging.dict()),
        None,
    )?;

    let all = logging.index()?;
    all.append("HostHandler")?;

    Ok(())
}
fn parse_memory_pool_id(memory_pool_id: PyObject, py: Python<'_>) -> eyre::Result<String> {
    let array_data = arrow::array::ArrayData::from_pyarrow_bound(memory_pool_id.bind(py))?;
    let array = arrow::array::make_array(array_data);

    if let Some(string_array) = array.as_any().downcast_ref::<StringArray>() {
        if string_array.len() != 1 {
            eyre::bail!(
                "expected string array with exactly one element, got {}",
                string_array.len()
            );
        }
        Ok(string_array.value(0).to_string())
    } else if let Some(binary_array) = array.as_any().downcast_ref::<BinaryArray>() {
        if binary_array.len() != 1 {
            eyre::bail!(
                "expected binary array with exactly one element, got {}",
                binary_array.len()
            );
        }
        Ok(String::from_utf8(binary_array.value(0).to_vec())?)
    } else {
        eyre::bail!(
            "memory_pool_id must be a string or binary array, got {:?}",
            array.data_type()
        )
    }
}

fn warn_missing_memory_pool(node_id: &NodeId, action: &str, buffer_id: &str) {
    tracing::warn!(
        "[{}] Attempt to {} memory pool [{}] failed - reason: pool does not exist. Operation aborted.",
        node_id,
        action,
        buffer_id
    );
}

/// The custom node API lets you integrate `dora` into your application.
/// It allows you to retrieve input and send output in any fashion you want.
///
/// Use with:
///
/// ```python
/// from dora import Node
///
/// node = Node()
/// ```
///
/// :type node_id: str, optional
#[pyclass]
#[derive(Dir, Dict, Str, Repr)]
pub struct Node {
    events: Events,
    node: DelayedCleanup<DoraNode>,

    dataflow_id: DataflowId,
    node_id: NodeId,
}

#[pymethods]
impl Node {
    #[new]
    #[pyo3(signature = (node_id=None, daemon_port=None))]
    pub fn new(node_id: Option<String>, daemon_port: Option<u16>) -> eyre::Result<Self> {
        let (node, events) = if let Some(node_id) = node_id {
            if let Some(port) = daemon_port {
                // Explicit port: always use builder with dynamic mode
                DoraNode::builder()
                    .node_id(NodeId::from(node_id))
                    .dynamic()
                    .daemon_port(port)
                    .build()
            } else {
                // No explicit port: try DORA_NODE_CONFIG first, fall back to dynamic
                DoraNode::init_flexible(NodeId::from(node_id))
            }
            .context("Could not setup node from node id. Make sure to have a running dataflow with this dynamic node")?
        } else {
            DoraNode::init_from_env().context("Could not initiate node from environment variable. For dynamic node, please add a node id in the initialization function.")?
        };
        let id = node.id().clone();
        let dataflow_id = node.dataflow_id().clone();
        RUNTIME.spawn(async move {
            let _guard = init_tracing(&id, &dataflow_id).unwrap();
            loop {
                tokio::time::sleep(std::time::Duration::from_secs(1)).await;
            }
        });

        let dataflow_id = *node.dataflow_id();
        let node_id = node.id().clone();
        let node = DelayedCleanup::new(node);
        let cleanup_handle = NodeCleanupHandle {
            _handles: Arc::new(node.handle()),
        };

        Python::with_gil(|py| {
            // Extend the `logging` module to interact with tracing
            setup_logging(py)
        })?;

        Ok(Node {
            events: Events {
                inner: Arc::new(Mutex::new(EventsInner::Dora(events))),
                _cleanup_handle: cleanup_handle,
            },
            dataflow_id,
            node_id,
            node,
        })
    }

    /// `.next()` gives you the next input that the node has received.
    /// It blocks until the next event becomes available.
    /// You can use timeout in seconds to return if no input is available.
    /// It will return `None` when all senders has been dropped.
    ///
    /// ```python
    /// event = node.next()
    /// ```
    ///
    /// You can also iterate over the event stream with a loop
    ///
    /// ```python
    /// for event in node:
    ///    match event["type"]:
    ///        case "INPUT":
    ///            match event["id"]:
    ///                 case "image":
    /// ```
    ///
    /// :type timeout: float, optional
    /// :rtype: dict
    #[pyo3(signature = (timeout=None))]
    #[allow(clippy::should_implement_trait)]
    pub fn next(&self, py: Python, timeout: Option<f32>) -> PyResult<Option<Py<PyDict>>> {
        let event = py.allow_threads(|| self.events.recv(timeout.map(Duration::from_secs_f32)))?;
        if let Some(event) = event {
            let dict = event
                .to_py_dict(py)
                .context("Could not convert event into a dict")?;
            Ok(Some(dict))
        } else {
            Ok(None)
        }
    }

    /// `.drain()` gives you all available inputs that the node has received.
    /// It does not block until the next event becomes available.
    ///
    /// ```python
    /// events = node.drain()
    /// for event in events:
    ///     print(event)
    /// ```
    ///
    /// :rtype: list[dict]
    #[allow(clippy::should_implement_trait)]
    pub fn drain(&self, py: Python) -> PyResult<Vec<Py<PyDict>>> {
        let events = self
            .events
            .drain()
            .context("Could not drain events. Channel is closed")?
            .into_iter()
            .map(|event| {
                event
                    .to_py_dict(py)
                    .context("Could not convert event into a dict")
                    .unwrap_or_else(|_| PyDict::new(py).into())
            })
            .collect();
        Ok(events)
    }

    /// `.try_recv()` gives you the next input in the queue that the node has received.
    /// It does not block until the next event becomes available.
    ///
    /// ```python
    /// event = events.try_recv()
    ///     print(event)
    /// ```
    ///
    /// :rtype: dict
    #[allow(clippy::should_implement_trait)]
    pub fn try_recv(&mut self, py: Python) -> PyResult<Option<Py<PyDict>>> {
        Ok(match self.events.try_recv()? {
            Ok(event) => match event.to_py_dict(py) {
                Ok(dict) => Some(dict),
                Err(_) => None,
            },
            Err(_) => None,
        })
    }

    /// Check if there are any buffered events in the event stream.
    ///
    /// :rtype: bool
    #[allow(clippy::should_implement_trait)]
    pub fn is_empty(&self) -> bool {
        self.events.is_empty()
    }

    /// `.recv_async()` gives you the next input that the node has received asynchronously.
    /// It does not blocks until the next event becomes available.
    /// You can use timeout in seconds to return if no input is available.
    /// It will return an Error if the timeout is reached.
    /// It will return `None` when all senders has been dropped.
    ///
    /// warning::
    ///     This feature is experimental as pyo3 async (rust-python FFI) is still in development.
    ///
    /// ```python
    /// event = await node.recv_async()
    /// ```
    ///
    /// You can also iterate over the event stream with a loop
    ///
    /// :type timeout: float, optional
    /// :rtype: dict
    #[pyo3(signature = (timeout=None))]
    #[allow(clippy::should_implement_trait)]
    pub async fn recv_async(&self, timeout: Option<f32>) -> PyResult<Option<Py<PyDict>>> {
        let event = self
            .events
            .recv_async_timeout(timeout.map(Duration::from_secs_f32))
            .await?;
        if let Some(event) = event {
            // Get python
            Python::with_gil(|py| {
                let dict = event
                    .to_py_dict(py)
                    .context("Could not convert event into a dict")?;

                Ok(Some(dict))
            })
        } else {
            Ok(None)
        }
    }

    /// You can iterate over the event stream with a loop
    ///
    /// ```python
    /// for event in node:
    ///    match event["type"]:
    ///        case "INPUT":
    ///            match event["id"]:
    ///                 case "image":
    /// ```
    ///
    /// Default behaviour is to timeout after 2 seconds.
    ///
    /// :rtype: dict
    pub fn __next__(&self, py: Python) -> PyResult<Option<Py<PyDict>>> {
        self.next(py, None)
    }

    /// You can iterate over the event stream with a loop
    ///
    /// ```python
    /// for event in node:
    ///    match event["type"]:
    ///        case "INPUT":
    ///            match event["id"]:
    ///                 case "image":
    /// ```
    ///
    /// :rtype: dict
    fn __iter__(slf: PyRef<'_, Self>) -> PyRef<'_, Self> {
        slf
    }

    /// `send_output` send data from the node.
    ///
    /// ```python
    /// Args:
    ///    output_id: str,
    ///    data: pyarrow.Array,
    ///    metadata: Option[Dict],
    /// ```
    ///
    /// ex:
    ///
    /// ```python
    /// node.send_output("string", b"string", {"open_telemetry_context": "7632e76"})
    /// ```
    ///
    /// :type output_id: str
    /// :type data: pyarrow.Array
    /// :type metadata: dict, optional
    /// :rtype: None
    #[pyo3(signature = (output_id, data, metadata=None))]
    pub fn send_output(
        &self,
        output_id: String,
        data: PyObject,
        metadata: Option<Bound<'_, PyDict>>,
        py: Python,
    ) -> eyre::Result<()> {
        let parameters = pydict_to_metadata(metadata)?;

        if let Ok(py_bytes) = data.downcast_bound::<PyBytes>(py) {
            let data = py_bytes.as_bytes();
            self.node
                .get_mut()
                .send_output_bytes(output_id.into(), parameters, data.len(), data)
                .wrap_err("failed to send output")?;
        } else if let Ok(arrow_array) = arrow::array::ArrayData::from_pyarrow_bound(data.bind(py)) {
            self.node.get_mut().send_output(
                output_id.into(),
                parameters,
                arrow::array::make_array(arrow_array),
            )?;
        } else {
            eyre::bail!("invalid `data` type, must by `PyBytes` or arrow array")
        }

        Ok(())
    }

    /// Returns the full dataflow descriptor that this node is part of.
    ///
    /// This method returns the parsed dataflow YAML file.
    ///
    /// :rtype: dict
    pub fn dataflow_descriptor(&self, py: Python) -> eyre::Result<PyObject> {
        Ok(
            pythonize::pythonize(py, &self.node.get_mut().dataflow_descriptor()?)
                .map(|x| x.unbind())?,
        )
    }

    /// Returns the node configuration.
    ///
    /// :rtype: dict
    pub fn node_config(&self, py: Python) -> eyre::Result<PyObject> {
        Ok(pythonize::pythonize(py, &self.node.get_mut().node_config()).map(|x| x.unbind())?)
    }

    /// Returns the dataflow id.
    ///
    /// :rtype: str
    pub fn dataflow_id(&self) -> String {
        self.dataflow_id.to_string()
    }

    /// Merge an external event stream with dora main loop.
    /// This currently only work with ROS2.
    ///
    /// :type subscription: dora.Ros2Subscription
    /// :rtype: None
    pub fn merge_external_events(&self, subscription: &mut Ros2Subscription) -> eyre::Result<()> {
        let subscription = subscription.into_stream()?;
        let stream = futures::stream::poll_fn(move |cx| {
            let s = subscription.as_stream().map(|item| {
                match item.context("failed to read ROS2 message") {
                    Ok((value, _info)) => Python::with_gil(|py| {
                        value
                            .to_pyarrow(py)
                            .context("failed to convert value to pyarrow")
                            .unwrap_or_else(|err| err_to_pyany(err, py))
                    }),
                    Err(err) => Python::with_gil(|py| err_to_pyany(err, py)),
                }
            });
            futures::pin_mut!(s);
            s.poll_next_unpin(cx)
        });

        // take out the event stream and temporarily replace it with a dummy
        let mut inner = self.events.inner.blocking_lock();
        let events = std::mem::replace(
            &mut *inner,
            EventsInner::Merged(Box::new(futures::stream::empty())),
        );
        // update self.events with the merged stream
        *inner = EventsInner::Merged(Box::new(events.merge_external_send(Box::pin(stream))));

        Ok(())
    }

    // === Memory Pool API ===

    /// Register a shared memory pool for zero-copy tensor transfer.
    #[pyo3(signature = (tensor_info, device))]
    pub fn register_memory_pool(
        &self,
        tensor_info: &Bound<'_, PyDict>,
        device: String,
        py: Python,
    ) -> eyre::Result<PyObject> {
        let ptr_val: u64 = tensor_info.get_item("ptr")?.unwrap().extract()?;
        let size: usize = tensor_info.get_item("size")?.unwrap().extract()?;
        let dtype: String = tensor_info.get_item("dtype")?.unwrap().extract()?;
        let shape_list: Vec<i64> = tensor_info.get_item("shape")?.unwrap().extract()?;
        let tensor_device: String =
            tensor_info.get_item("device")?.unwrap().extract()?;

        let is_cuda = tensor_device.starts_with("cuda");
        let receiver_is_cuda = device.starts_with("cuda");
        let cpu_mode = !receiver_is_cuda;

        if ptr_val == 0 {
            eyre::bail!("Invalid source pointer (NULL)");
        }
        if size == 0 || size > 1024 * 1024 * 1024 {
            eyre::bail!("Invalid size: {} bytes", size);
        }

        // Generate unique pool counter for this registration
        let pool_counter = {
            let mut c = PINNED_COUNTER.lock().unwrap();
            *c += 1;
            *c
        };
        let shmem_name = format!("dora_pool_{}", pool_counter);

        // DORADMA header setup
        const HEADER_SIZE: usize = 256;
        const HEADER_MAGIC: &[u8; 8] = b"DORADMA\x00";
        const METADATA_ALIGN: usize = 256;

        let header_meta = PyDict::new(py);
        header_meta.set_item("size", size)?;
        header_meta.set_item("dtype", &dtype)?;
        header_meta.set_item("shape", shape_list.clone())?;
        header_meta.set_item(
            "pinned_type",
            if cpu_mode { "cpu" } else { "cuda" },
        )?;

        let json_bytes = py
            .import("json")
            .wrap_err("failed to import json")?
            .call_method1("dumps", (header_meta,))
            .wrap_err("failed to serialize metadata to JSON")?
            .extract::<String>()
            .wrap_err("failed to extract JSON string")?
            .into_bytes();
        let json_len = json_bytes.len();
        let padded_json_len =
            ((json_len + METADATA_ALIGN - 1) / METADATA_ALIGN) * METADATA_ALIGN;
        let data_offset = HEADER_SIZE + padded_json_len;
        let total_size = data_offset + size;

        // Create/find shared memory
        let (shmem, shmem_ptr, sender_gpu_va) = 'pool: loop {
            let mut pool = PINNED_POOL.lock().unwrap();
            if let Some(old_slot) = pool.remove(&pool_counter) {
                if old_slot.size >= total_size {
                    break 'pool (old_slot._shmem, old_slot.base as *mut u8, old_slot.gpu_va);
                }
            }
            drop(pool);

            let mut new_shmem = match ShmemConf::new()
                .os_id(&shmem_name)
                .size(total_size)
                .writable(true)
                .create()
            {
                Ok(s) => s,
                Err(_) => ShmemConf::new()
                    .os_id(&shmem_name)
                    .writable(true)
                    .open()
                    .wrap_err("failed to open pool shared memory")?,
            };
            let new_ptr = unsafe { new_shmem.as_slice_mut().as_mut_ptr() };

            let mut gpu_va = 0u64;
            if let Ok(helpers) = get_cuda_helpers(py) {
                let bound = helpers.bind(py);
                let _ =
                    bound.call_method1("_register_host", (new_ptr as u64, total_size));
                if !cpu_mode {
                    if let Ok(va) =
                        bound.call_method1("_get_device_ptr", (new_ptr as u64,))
                    {
                        gpu_va = va.extract::<u64>().unwrap_or(0);
                    }
                }
            }

            new_shmem.set_owner(false);
            break 'pool (new_shmem, new_ptr, gpu_va);
        };

        // Write DORADMA header
        unsafe {
            std::ptr::copy_nonoverlapping(HEADER_MAGIC.as_ptr(), shmem_ptr, 8);
            let json_len_le = (json_len as u64).to_le_bytes();
            std::ptr::copy_nonoverlapping(json_len_le.as_ptr(), shmem_ptr.add(8), 8);
            let data_off_le = (data_offset as u64).to_le_bytes();
            std::ptr::copy_nonoverlapping(data_off_le.as_ptr(), shmem_ptr.add(16), 8);
            std::ptr::copy_nonoverlapping(
                json_bytes.as_ptr(),
                shmem_ptr.add(HEADER_SIZE),
                json_len,
            );
        }

        // Copy tensor data to shmem
        if is_cuda {
            if let Ok(helpers) = get_cuda_helpers(py) {
                let bound = helpers.bind(py);
                let _ = bound.call_method1(
                    "_cuda_memcpy",
                    (shmem_ptr as u64 + data_offset as u64, ptr_val, size, 2u32),
                );
            }
        } else {
            unsafe {
                std::ptr::copy_nonoverlapping(
                    ptr_val as *const u8,
                    shmem_ptr.add(data_offset),
                    size,
                );
            }
        }

        // GPU pool: DMA data into pooled GPU buffer + IPC export.
        // Receiver imports the handle once (cudaIpcOpenMemHandle) and
        // reads from GPU DRAM with zero copy thereafter.
        if receiver_is_cuda {
            if let Ok(helpers) = get_cuda_helpers(py) {
                let bound = helpers.bind(py);
                if let Ok(gpu_ptr) = bound
                    .call_method1("dma_copy", (ptr_val, size, pool_counter))
                    .and_then(|r| r.extract::<u64>())
                {
                    if let Ok(handle) = bound
                        .call_method1("_ipc_export", (gpu_ptr,))
                        .and_then(|r| r.extract::<Vec<u8>>())
                    {
                        if handle.len() == 64 {
                            unsafe {
                                // Write IPC handle into DORADMA reserved area [32..96)
                                std::ptr::copy_nonoverlapping(
                                    handle.as_ptr(),
                                    shmem_ptr.add(32),
                                    64,
                                );
                                // ipc_present flag at byte 24
                                std::ptr::write(shmem_ptr.add(24) as *mut u64, 1u64);
                            }
                        }
                    }
                }
            }
        }

        // Store shmem in pool (keep alive)
        {
            let mut pool = PINNED_POOL.lock().unwrap();
            pool.insert(pool_counter, PoolSlot {
                _shmem: shmem,
                base: shmem_ptr as u64,
                size: total_size,
                gpu_va: sender_gpu_va,
            });
        }

        let buffer_id = format!("pool_{}", pool_counter);

        // Register with daemon for lifecycle tracking
        {
            use arrow::datatypes::DataType;
            use dora_node_api::dora_core::metadata::ArrowTypeInfo;

            let hlc = dora_node_api::dora_core::uhlc::HLC::default();
            let ts = hlc.new_timestamp();
            let mut params = dora_node_api::MetadataParameters::new();
            params.insert(
                "ptr".to_string(),
                dora_node_api::Parameter::Integer(ptr_val as i64),
            );
            params.insert(
                "size".to_string(),
                dora_node_api::Parameter::Integer(size as i64),
            );
            params.insert(
                "dtype".to_string(),
                dora_node_api::Parameter::String(dtype),
            );
            params.insert(
                "shape".to_string(),
                dora_node_api::Parameter::ListInt(shape_list),
            );
            params.insert(
                "shared_memory_name".to_string(),
                dora_node_api::Parameter::String(shmem_name),
            );
            params.insert(
                "is_pinned".to_string(),
                dora_node_api::Parameter::Bool(true),
            );
            params.insert(
                "buffer_id".to_string(),
                dora_node_api::Parameter::String(buffer_id.clone()),
            );

            let type_info = ArrowTypeInfo {
                data_type: DataType::Null,
                len: 0,
                null_count: 0,
                validity: None,
                offset: 0,
                buffer_offsets: vec![],
                child_data: vec![],
            };
            let meta =
                dora_node_api::Metadata::from_parameters(ts, type_info, params);
            if let Err(e) =
                self.node
                    .get_mut()
                    .register_pinned_memory(buffer_id.clone(), meta)
            {
                tracing::warn!(
                    "[{}] failed to register memory pool: {:#}",
                    self.node_id,
                    e
                );
            }
        }

        let buffer_id_array = arrow::array::StringArray::from(vec![buffer_id]);
        let buf_py: PyObject = buffer_id_array.to_data().to_pyarrow(py)?;
        Ok(buf_py)
    }

    /// Write tensor data to an existing memory pool.
    #[pyo3(signature = (memory_pool_id, tensor_info))]
    pub fn write_memory_pool(
        &self,
        memory_pool_id: PyObject,
        tensor_info: &Bound<'_, PyDict>,
        py: Python,
    ) -> eyre::Result<()> {
        let buffer_id = parse_memory_pool_id(memory_pool_id, py)?;

        let ptr_val: u64 = tensor_info.get_item("ptr")?.unwrap().extract()?;
        let size: usize = tensor_info.get_item("size")?.unwrap().extract()?;
        let tensor_device: String =
            tensor_info.get_item("device")?.unwrap().extract()?;
        let is_cuda = tensor_device.starts_with("cuda");

        {
            let freed = FREED_POOL_IDS.lock().unwrap();
            if freed.contains(&buffer_id) {
                warn_missing_memory_pool(&self.node_id, "write", &buffer_id);
                return Ok(());
            }
        }

        // Fast path: pool_ format -> DORADMA
        if buffer_id.starts_with("pool_") {
            let parts: Vec<&str> = buffer_id.split('_').collect();
            if parts.len() >= 2 {
                if let Ok(counter) = parts[1].parse::<u64>() {
                    const HEADER_MAGIC: &[u8; 8] = b"DORADMA\x00";

                    // Try PINNED_POOL cache first to avoid per-iteration mmap/munmap.
                    // register_memory_pool already stored the Shmem here; taking it
                    // prevents munmap, and storing it back keeps the mapping alive.
                    let pool_slot = { PINNED_POOL.lock().unwrap().remove(&counter) };

                    let (shmem_ptr, store_back) = if let Some(slot_data) = pool_slot {
                        // Cache hit: reuse the persistent mapping (no mmap)
                        (slot_data.base as *mut u8, Some(slot_data))
                    } else {
                        // Cache miss: open via ShmemConf (mmap, slower)
                        let shmem_name = format!("dora_pool_{}", counter);
                        match ShmemConf::new().os_id(&shmem_name).open() {
                            Ok(shmem) => (shmem.as_ptr(), None),
                            Err(_) => (std::ptr::null_mut(), None),
                        }
                    };

                    if !shmem_ptr.is_null() {
                        let magic =
                            unsafe { std::slice::from_raw_parts(shmem_ptr, 8) };
                        if magic == HEADER_MAGIC {
                            let data_offset = unsafe {
                                u64::from_le_bytes(
                                    std::slice::from_raw_parts(shmem_ptr.add(16), 8)
                                        .try_into()
                                        .unwrap(),
                                ) as usize
                            };

                            // Check if this pool has GPU DMA path enabled
                            let ipc_present = unsafe {
                                std::ptr::read(shmem_ptr.add(24) as *const u64)
                            };

                            if ipc_present == 1 && !is_cuda {
                                // DMA: source CPU data -> GPU pool buffer via DMA engine
                                if let Ok(helpers) = get_cuda_helpers(py) {
                                    let bound = helpers.bind(py);
                                    let _ = bound.call_method1(
                                        "dma_copy", (ptr_val, size, counter),
                                    );
                                }
                            } else if is_cuda {
                                if let Ok(helpers) = get_cuda_helpers(py) {
                                    let bound = helpers.bind(py);
                                    let _ = bound.call_method1(
                                        "_cuda_memcpy",
                                        (
                                            shmem_ptr as u64 + data_offset as u64,
                                            ptr_val,
                                            size,
                                            2u32,
                                        ),
                                    );
                                }
                            } else {
                                unsafe {
                                    std::ptr::copy_nonoverlapping(
                                        ptr_val as *const u8,
                                        shmem_ptr.add(data_offset),
                                        size,
                                    );
                                }
                            }

                            // Store back to PINNED_POOL to keep shmem alive
                            if let Some(slot_data) = store_back {
                                PINNED_POOL.lock().unwrap().insert(counter, slot_data);
                            }

                            return Ok(());
                        }
                    }
                }
            }
        }

        // Slow path: query daemon for pool metadata
        match self
            .node
            .get_mut()
            .read_pinned_memory(buffer_id.clone(), false)
        {
            Ok(metadata) => {
                let shmem_name = metadata
                    .parameters
                    .get("shared_memory_name")
                    .and_then(|p| {
                        if let Parameter::String(s) = p {
                            Some(s.clone())
                        } else {
                            None
                        }
                    });

                if let Some(ref name) = shmem_name {
                    if let Ok(shmem) = ShmemConf::new().os_id(name).open() {
                        let shmem_ptr = shmem.as_ptr();

                        const HEADER_MAGIC: &[u8; 8] = b"DORADMA\x00";
                        let magic =
                            unsafe { std::slice::from_raw_parts(shmem_ptr, 8) };
                        if magic == HEADER_MAGIC {
                            let data_offset = unsafe {
                                u64::from_le_bytes(
                                    std::slice::from_raw_parts(shmem_ptr.add(16), 8)
                                        .try_into()
                                        .unwrap(),
                                ) as usize
                            };

                            if is_cuda {
                                if let Ok(helpers) = get_cuda_helpers(py) {
                                    let bound = helpers.bind(py);
                                    let _ = bound.call_method1(
                                        "_cuda_memcpy",
                                        (
                                            shmem_ptr as u64 + data_offset as u64,
                                            ptr_val,
                                            size,
                                            2u32,
                                        ),
                                    );
                                }
                            } else {
                                unsafe {
                                    std::ptr::copy_nonoverlapping(
                                        ptr_val as *const u8,
                                        shmem_ptr.add(data_offset),
                                        size,
                                    );
                                }
                            }
                        }
                    }
                }
            }
            Err(_) => {
                warn_missing_memory_pool(&self.node_id, "write", &buffer_id);
            }
        }

        Ok(())
    }

    /// Read tensor info from an existing memory pool (zero-copy).
    ///
    /// Returns tensor_info dict compatible with tensor_from_info.
    #[pyo3(signature = (memory_pool_id))]
    pub fn read_memory_pool(
        &self,
        memory_pool_id: PyObject,
        py: Python,
    ) -> eyre::Result<PyObject> {
        let buffer_id = parse_memory_pool_id(memory_pool_id, py)?;

        // Fast path: DORADMA header read
        if buffer_id.starts_with("pool_") {
            if let Some(result) = self.try_doradma_read(&buffer_id, py)? {
                return Ok(result);
            }
            tracing::debug!("[{}] read_memory_pool: fast path returned None, falling back to daemon", self.node_id);
        }

        // Slow path: query daemon
        match self
            .node
            .get_mut()
            .read_pinned_memory(buffer_id.clone(), false)
        {
            Ok(metadata) => {
                let dict = PyDict::new(py);

                let ptr = metadata
                    .parameters
                    .get("ptr")
                    .and_then(|p| {
                        if let Parameter::Integer(v) = p {
                            Some(*v)
                        } else {
                            None
                        }
                    })
                    .unwrap_or(0);
                let size = metadata
                    .parameters
                    .get("size")
                    .and_then(|p| {
                        if let Parameter::Integer(v) = p {
                            Some(*v)
                        } else {
                            None
                        }
                    })
                    .unwrap_or(0);
                let dtype = metadata
                    .parameters
                    .get("dtype")
                    .and_then(|p| {
                        if let Parameter::String(s) = p {
                            Some(s.clone())
                        } else {
                            None
                        }
                    })
                    .unwrap_or_default();
                let shape = metadata
                    .parameters
                    .get("shape")
                    .and_then(|p| {
                        if let Parameter::ListInt(v) = p {
                            Some(v.clone())
                        } else {
                            None
                        }
                    })
                    .unwrap_or_default();

                dict.set_item("ptr", ptr)?;
                dict.set_item("size", size)?;
                dict.set_item("dtype", dtype)?;
                dict.set_item("shape", shape)?;
                dict.set_item("device", "cpu")?;

                Ok(dict.into())
            }
            Err(e) => {
                warn_missing_memory_pool(&self.node_id, "read", &buffer_id);
                tracing::debug!("[{}] read_memory_pool: daemon error: {:?}", self.node_id, e);
                let dict = PyDict::new(py);
                dict.set_item("ptr", 0)?;
                dict.set_item("size", 0)?;
                dict.set_item("dtype", "int64")?;
                dict.set_item("shape", vec![0i64])?;
                dict.set_item("device", "cpu")?;
                Ok(dict.into())
            }
        }
    }

    /// Free a memory pool.
    #[pyo3(signature = (memory_pool_id))]
    pub fn free_memory_pool(
        &self,
        memory_pool_id: PyObject,
        py: Python,
    ) -> eyre::Result<()> {
        let buffer_id = parse_memory_pool_id(memory_pool_id, py)?;

        match self.node.get_mut().free_pinned_memory(buffer_id.clone()) {
            Ok(_) => {}
            Err(_) => {
                warn_missing_memory_pool(&self.node_id, "release", &buffer_id);
            }
        }
        {
            let mut freed = FREED_POOL_IDS.lock().unwrap();
            tracing::debug!("[{}] free_memory_pool: adding {} to FREED_POOL_IDS (set size={})", self.node_id, buffer_id, freed.len());
            freed.insert(buffer_id);
        }

        Ok(())
    }

}

fn err_to_pyany(err: eyre::Report, gil: Python<'_>) -> Py<PyAny> {
    PyErr::from(err)
        .into_pyobject(gil)
        .unwrap_or_else(|infallible| match infallible {})
        .into_any()
        .unbind()
}

struct Events {
    inner: Arc<Mutex<EventsInner>>,
    _cleanup_handle: NodeCleanupHandle,
}

impl Events {
    fn recv(&self, timeout: Option<Duration>) -> PyResult<Option<PyEvent>> {
        let mut inner = self.inner.blocking_lock();
        let event = match &mut *inner {
            EventsInner::Dora(events) => {
                if events.is_closed() {
                    return Err(eyre::eyre!("cannot receive from closed event stream").into());
                }
                match timeout {
                    Some(timeout) => events.recv_timeout(timeout).map(MergedEvent::Dora),
                    None => events.recv().map(MergedEvent::Dora),
                }
            }
            EventsInner::Merged(events) => futures::executor::block_on(events.next()),
        };
        Ok(event.map(|event| PyEvent { event }))
    }

    fn try_recv(&self) -> PyResult<Result<PyEvent, TryRecvError>> {
        let mut inner = self.inner.blocking_lock();
        let event = match &mut *inner {
            EventsInner::Dora(events) => {
                if events.is_closed() {
                    return Err(eyre::eyre!("cannot receive from closed event stream").into());
                }
                events.try_recv().map(MergedEvent::Dora)
            }
            EventsInner::Merged(_events) => {
                todo!("try_recv on external event stream is not yet implemented!")
            }
        };
        Ok(event.map(|event| PyEvent { event }))
    }

    async fn recv_async_timeout(&self, timeout: Option<Duration>) -> PyResult<Option<PyEvent>> {
        let mut inner = self.inner.lock().await;
        let event = match &mut *inner {
            EventsInner::Dora(events) => {
                if events.is_closed() {
                    return Err(eyre::eyre!("cannot receive from closed event stream").into());
                }
                match timeout {
                    Some(timeout) => events
                        .recv_async_timeout(timeout)
                        .await
                        .map(MergedEvent::Dora),
                    None => events.recv_async().await.map(MergedEvent::Dora),
                }
            }
            EventsInner::Merged(events) => events.next().await,
        };
        Ok(event.map(|event| PyEvent { event }))
    }

    fn drain(&self) -> Option<Vec<PyEvent>> {
        let mut inner = self.inner.blocking_lock();
        match &mut *inner {
            EventsInner::Dora(events) => match events.drain() {
                Some(items) => {
                    return Some(
                        items
                            .into_iter()
                            .map(MergedEvent::Dora)
                            .map(|event| PyEvent { event })
                            .collect(),
                    );
                }
                None => return None,
            },
            EventsInner::Merged(_events) => {
                todo!("Draining external event is not yet implemented!")
            }
        };
    }

    fn is_empty(&self) -> bool {
        let inner = self.inner.blocking_lock();
        match &*inner {
            EventsInner::Dora(events) => events.is_empty(),
            EventsInner::Merged(_events) => {
                todo!("is_empty on external event stream is not yet implemented!")
            }
        }
    }
}

#[allow(clippy::large_enum_variant)]
enum EventsInner {
    Dora(EventStream),
    Merged(Box<dyn Stream<Item = MergedEvent<PyObject>> + Unpin + Send + Sync>),
}

impl<'a> MergeExternalSend<'a, PyObject> for EventsInner {
    type Item = MergedEvent<PyObject>;

    fn merge_external_send(
        self,
        external_events: impl Stream<Item = PyObject> + Unpin + Send + Sync + 'a,
    ) -> impl Stream<Item = Self::Item> + Unpin + Send + Sync + 'a {
        let stream: Box<dyn Stream<Item = Self::Item> + Unpin + Send + Sync + 'a> = match self {
            EventsInner::Dora(events) => Box::new(events.merge_external_send(external_events)),
            EventsInner::Merged(events) => {
                let merged = events.merge_external_send(external_events);
                Box::new(merged.map(|event| match event {
                    MergedEvent::Dora(e) => MergedEvent::Dora(e),
                    MergedEvent::External(e) => MergedEvent::External(e.flatten()),
                }))
            }
        };
        stream
    }
}

impl Node {
    pub fn id(&self) -> String {
        self.node_id.to_string()
    }

    /// DORADMA fast path for read_memory_pool: reads metadata directly from
    /// the shmem header, bypassing the daemon for zero-copy metadata retrieval.
    ///
    /// Buffer ID format: "pool_{counter}" → shmem name: "dora_pool_{counter}"
    ///
    /// Returns `Ok(Some(tensor_info_dict))` on success, `Ok(None)` to fall back to daemon.
    fn try_doradma_read(
        &self,
        buffer_id: &str,
        py: Python<'_>,
    ) -> eyre::Result<Option<PyObject>> {
        // Extract counter from "pool_{counter}"
        let parts: Vec<&str> = buffer_id.split('_').collect();
        if parts.len() < 2 {
            return Ok(None);
        }
        let counter: u64 = match parts[1].parse() {
            Ok(s) => s,
            Err(_) => return Ok(None),
        };

        // Check freed tracking — if this buffer was freed, fall back to daemon
        {
            let freed = FREED_POOL_IDS.lock().unwrap();
            if freed.contains(buffer_id) {
                tracing::debug!("[{}] try_doradma_read: buffer {} is freed, fallback to daemon", self.node_id, buffer_id);
                return Ok(None);
            }
        }

        let shmem_name = format!("dora_pool_{}", counter);

        // Open shared memory
        let shmem = match ShmemConf::new().os_id(&shmem_name).open() {
            Ok(s) => s,
            Err(_) => return Ok(None),
        };

        let shmem_ptr = shmem.as_ptr();
        let shmem_size = shmem.len();

        // Verify DORADMA magic header
        const HEADER_MAGIC: &[u8; 8] = b"DORADMA\x00";
        const HEADER_SIZE: usize = 256;

        unsafe {
            let magic = std::slice::from_raw_parts(shmem_ptr, 8);
            if magic != HEADER_MAGIC {
                return Ok(None);
            }
        }

        // Read header: [magic:8][json_len:8][data_offset:8][reserved:232]
        let json_len = unsafe {
            u64::from_le_bytes(
                (std::slice::from_raw_parts(shmem_ptr.add(8), 8))
                    .try_into()
                    .unwrap(),
            ) as usize
        };
        let data_offset = unsafe {
            u64::from_le_bytes(
                (std::slice::from_raw_parts(shmem_ptr.add(16), 8))
                    .try_into()
                    .unwrap(),
            ) as usize
        };

        // Read JSON metadata from header
        let json_slice = unsafe { std::slice::from_raw_parts(shmem_ptr.add(HEADER_SIZE), json_len) };
        let json_str = match std::str::from_utf8(json_slice) {
            Ok(s) => s,
            Err(_) => return Ok(None),
        };

        // Parse JSON to Python dict
        let metadata_dict: Bound<'_, PyDict> = match py.import("json") {
            Ok(m) => match m.call_method1("loads", (json_str,)) {
                Ok(v) => match v.downcast_into::<PyDict>() {
                    Ok(d) => d,
                    Err(_) => return Ok(None),
                },
                Err(_) => return Ok(None),
            },
            Err(_) => return Ok(None),
        };

        let size: usize = match metadata_dict.get_item("size") {
            Ok(Some(v)) => v.extract().unwrap_or(0),
            _ => 0,
        };
        if size == 0 {
            return Ok(None);
        }

        // Auto-detect read path from pinned_type
        let pinned_type: Option<String> = metadata_dict
            .get_item("pinned_type").ok().flatten()
            .and_then(|v| v.extract::<String>().ok());
        // Check if this pool uses GPU DMA (IPC handle in header)
        let ipc_present = unsafe { std::ptr::read(shmem_ptr.add(24) as *const u64) };

        let host_ptr = shmem_ptr as u64 + data_offset as u64;
        let effective_as_cuda = ipc_present == 1
            || pinned_type.as_deref() != Some("cpu");

        let read_ptr: u64;

        if ipc_present == 1 {
            // GPU DMA pool: import IPC handle once, cache GPU buffer ptr
            read_ptr = {
                let cache = RECV_GPU_VA.lock().unwrap();
                match cache.get(&counter) {
                    Some(slot_data) if slot_data.gpu_buf != 0 => slot_data.gpu_buf,
                    _ => {
                        drop(cache);
                        let handle_bytes =
                            unsafe { std::slice::from_raw_parts(shmem_ptr.add(32), 64) };
                        let helpers = get_cuda_helpers(py)
                            .map_err(|e| eyre::eyre!("get_cuda_helpers: {}", e))?;
                        let bound = helpers.bind(py);
                        let handle_py = PyBytes::new(py, handle_bytes);
                        let gpu_ptr: u64 = bound
                            .call_method1("_ipc_import", (handle_py,))
                            .map_err(|e| eyre::eyre!("_ipc_import: {}", e))?
                            .extract()
                            .map_err(|e| eyre::eyre!("extract gpu_ptr: {}", e))?;
                        let mut cache = RECV_GPU_VA.lock().unwrap();
                        cache.insert(counter, RecvGpuSlot {
                            _shmem: shmem,
                            gpu_va: 0,
                            gpu_buf: gpu_ptr,
                        });
                        gpu_ptr
                    }
                }
            };
        } else if effective_as_cuda {
            read_ptr = {
                let cache = RECV_GPU_VA.lock().unwrap();
                match cache.get(&counter) {
                    Some(slot_data) => slot_data.gpu_va + data_offset as u64,
                    None => {
                        drop(cache);
                        let helpers = get_cuda_helpers(py)
                            .map_err(|e| eyre::eyre!("get_cuda_helpers: {}", e))?;
                        let bound = helpers.bind(py);
                        bound
                            .call_method1("_register_host", (shmem_ptr as u64, shmem_size))
                            .map_err(|e| eyre::eyre!("_register_host: {}", e))?;
                        let va: u64 = bound
                            .call_method1("_get_device_ptr", (shmem_ptr as u64,))
                            .map_err(|e| eyre::eyre!("_get_device_ptr: {}", e))?
                            .extract()
                            .map_err(|e| eyre::eyre!("extract gpu_va: {}", e))?;
                        let mut cache = RECV_GPU_VA.lock().unwrap();
                        cache.insert(counter, RecvGpuSlot {
                            _shmem: shmem,
                            gpu_va: va,
                            gpu_buf: 0,
                        });
                        va + data_offset as u64
                    }
                }
            };
        } else {
            read_ptr = shmem_ptr as u64 + data_offset as u64;
            let mut cpu_cache = RECV_CPU_SHMEM.lock().unwrap();
            if !cpu_cache.contains_key(&counter) {
                cpu_cache.insert(counter, RecvCpuSlot { _shmem: shmem });
            }
        }

        // Build tensor_info dict
        let dtype: String = metadata_dict
            .get_item("dtype")
            .ok().flatten()
            .and_then(|v| v.extract::<String>().ok())
            .unwrap_or_default();
        let shape: Vec<i64> = metadata_dict
            .get_item("shape")
            .ok().flatten()
            .and_then(|v| v.extract::<Vec<i64>>().ok())
            .unwrap_or_default();
        let device = if effective_as_cuda { "cuda" } else { "cpu" };

        let dict = PyDict::new(py);
        dict.set_item("ptr", read_ptr as i64)?;
        dict.set_item("host_ptr", host_ptr as i64)?;
        dict.set_item("size", size)?;
        dict.set_item("dtype", dtype)?;
        dict.set_item("shape", shape)?;
        dict.set_item("device", device)?;

        Ok(Some(dict.into()))
    }
}

/// Start a runtime for Operators
///
/// :rtype: None
#[pyfunction]
pub fn start_runtime() -> eyre::Result<()> {
    dora_runtime::main().wrap_err("Dora Runtime raised an error.")
}

pub fn resolve_dataflow(dataflow: String) -> eyre::Result<PathBuf> {
    let dataflow = if source_is_url(&dataflow) {
        // try to download the shared library
        let target_path = current_dir().context("Could not access the current dir")?;
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .context("tokio runtime failed")?;
        rt.block_on(async { download_file(&dataflow, &target_path).await })
            .wrap_err("failed to download dataflow yaml file")?
    } else {
        PathBuf::from(dataflow)
    };
    Ok(dataflow)
}

/// Build a Dataflow, exactly the same way as `dora build` command line tool.
///
///
/// :type dataflow_path: str
/// :type uv: bool, optional
/// :type coordinator_addr: str, optional
/// :type coordinator_port: int, optional
/// :type force_local: bool, optional
/// :rtype: None
#[pyfunction]
#[pyo3(signature = (dataflow_path, uv=None, coordinator_addr=None, coordinator_port=None, force_local=false))]
pub fn build(
    dataflow_path: String,
    uv: Option<bool>,
    coordinator_addr: Option<String>,
    coordinator_port: Option<u16>,
    force_local: bool,
) -> eyre::Result<()> {
    dora_cli::build(
        dataflow_path,
        coordinator_addr.map(|addr| addr.parse().unwrap()),
        coordinator_port,
        uv.unwrap_or_default(),
        force_local,
    )
}

/// Run a Dataflow, exactly the same way as `dora run` command line tool.
///
/// :type dataflow_path: str
/// :type uv: bool, optional
/// :type stop_after: float, optional
/// :rtype: None
#[pyfunction]
#[pyo3(signature = (dataflow_path, uv=None, stop_after=None))]
pub fn run(dataflow_path: String, uv: Option<bool>, stop_after: Option<f64>) -> eyre::Result<()> {
    use dora_cli::Executable;

    let stop_after_duration = stop_after.map(std::time::Duration::from_secs_f64);
    let mut run = dora_cli::RunCommand::new(dataflow_path);
    if let Some(uv) = uv {
        run.uv = uv;
    }
    if let Some(duration) = stop_after_duration {
        run.stop_after = Some(duration);
    }
    let rt = tokio::runtime::Builder::new_multi_thread()
        .enable_all()
        .build()
        .context("tokio runtime failed")?;
    rt.block_on(run.execute())
}

#[pymodule]
fn dora(_py: Python, m: Bound<'_, PyModule>) -> PyResult<()> {
    dora_ros2_bridge_python::create_dora_ros2_bridge_module(&m)?;

    m.add_function(wrap_pyfunction!(start_runtime, &m)?)?;
    m.add_function(wrap_pyfunction!(run, &m)?)?;
    m.add_function(wrap_pyfunction!(build, &m)?)?;
    m.add_class::<Node>()?;
    m.setattr("__version__", env!("CARGO_PKG_VERSION"))?;
    m.setattr("__author__", "Dora-rs Authors")?;

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use shared_memory_extended::ShmemConf;

    #[test]
    fn test_shmem_creation() {
        // Test that ShmemConf can create and write to shared memory
        let size = 8000;
        let shmem_conf = ShmemConf::new().size(size).writable(true);

        let mut shmem = shmem_conf.create().expect("failed to create shared memory");

        // Write to shared memory
        let slice = unsafe { shmem.as_slice_mut() };
        slice[0] = 0x42;
        assert_eq!(slice[0], 0x42);

        // Write pattern
        for i in 0..size.min(100) {
            slice[i] = (i % 256) as u8;
        }

        // Read back
        for i in 0..size.min(100) {
            assert_eq!(slice[i], (i % 256) as u8);
        }
    }
}
